// // This module implements a 8-bit register that loads data on the falling edge of the clock when the load signal is low.
module reg8 (
        input clk,
        input reset,
        input load,
        input [7:0] d,
        output reg [7:0] q);

    always @(posedge clk or posedge reset) begin
        if (reset)
            q <= 8'b00000000;
        else if (load)
            q <= d;
    end

endmodule
